sessionStart.powershell:
$retentionDays = if ($env:VSTACK_HOOKS_LOG_RETENTION_DAYS) { [int]$env:VSTACK_HOOKS_LOG_RETENTION_DAYS } else { '7' }
$cleanupDebug = if ($env:VSTACK_HOOKS_CLEANUP_LOG) { $env:VSTACK_HOOKS_CLEANUP_LOG } else { '0' }
$logRoot = if ($env:VSTACK_HOOK_LOG_DIR) { $env:VSTACK_HOOK_LOG_DIR } else { '.vstack/logs' }
New-Item -ItemType Directory -Force -Path $logRoot | Out-Null
$deletedCount = 0
$oldestDeletedDate = ''
$cleanupError = ''
if ($retentionDays -gt 0) {
  $threshold = (Get-Date).ToUniversalTime().Date.AddDays(-$retentionDays)
  Get-ChildItem $logRoot -Directory -ErrorAction SilentlyContinue |
    Where-Object {
      $_.Name -match '^\d{8}$' -and
      ([datetime]::ParseExact($_.Name, 'yyyyMMdd', [System.Globalization.CultureInfo]::InvariantCulture).Date -lt $threshold)
    } |
    ForEach-Object {
      try {
        Remove-Item -Path $_.FullName -Recurse -Force -ErrorAction Stop
        $deletedCount++
        if (-not $oldestDeletedDate -or $_.Name -lt $oldestDeletedDate) {
          $oldestDeletedDate = $_.Name
        }
      } catch {
        $cleanupError = 'delete-failed'
      }
    }
} else {
  $cleanupError = 'invalid-retention-days'
}

if ($cleanupDebug -eq '1' -or $deletedCount -gt 0 -or $cleanupError) {
  $logName = 'hook-retention-cleanup.log'
  $logDir = Join-Path $logRoot (Get-Date).ToUniversalTime().ToString('yyyyMMdd')
  New-Item -ItemType Directory -Force -Path $logDir | Out-Null
  $logPath = Join-Path $logDir $logName
  $entry = @{
    ts = (Get-Date).ToUniversalTime().ToString('yyyy-MM-ddTHH:mm:ssZ')
    event = 'retention-cleanup'
    retention_days = $retentionDays
    deleted_count = $deletedCount
    oldest_deleted_date = $oldestDeletedDate
    error = $cleanupError
  } | ConvertTo-Json -Compress
  Add-Content -Path $logPath -Value $entry
}
